{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleIssueTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class IndentationRuleIssueTest {
    private val indentationRuleAssertThat = KtLintAssertThat.assertThatRule { IndentationRule() }

    @Test
    fun `Issue - try catch expression with function assignment should not indent catch`() {
        val code =
            """
            fun test() = try {
              1
            }
            catch(_: Throwable) {
              2
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - typealias with multiline type should indent the type`() {
        val code =
            """
            typealias Foo =
              HashMap<Bar, Baz?>
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

