        var nextToAstNode = node.lastChildLeafOrSelf()

        // Process FINALLY block first (in reverse order)
        node
            .findChildByType(FINALLY)
            ?.let { finally ->
                val nodeAfterFinally = startIndentContext(
                    fromAstNode = finally,
                    toAstNode = nextToAstNode,
                )
                nextToAstNode = nodeAfterFinally.prevCodeLeaf()
            }

        // Process CATCH blocks in reverse order
        val catchBlocks = node.children().filter { it.elementType == CATCH }.toList().reversed()
        for (catchBlock in catchBlocks) {
            val nodeAfterCatch = startIndentContext(
                fromAstNode = catchBlock,
                toAstNode = nextToAstNode,
            )
            nextToAstNode = nodeAfterCatch.prevCodeLeaf()
        }

        // Handle the whitespace after TRY block to prevent extra indentation
        // Similar to how IF handles the whitespace after THEN block
        node
            .findChildByType(BLOCK)
            ?.lastChildLeafOrSelf()
            ?.nextLeaf()
            ?.let { nodeAfterTryBlock ->
                nextToAstNode = startIndentContext(
                    fromAstNode = nodeAfterTryBlock,
                    toAstNode = nextToAstNode,
                    childIndent = "",
                ).prevCodeLeaf()
            }

        startIndentContext(
            fromAstNode = node,
            toAstNode = nextToAstNode,
        )
    }"}

